var jumpToCode = (function init() {
    // Classes of code we would like to highlight in the file view
    var missingCoverageClasses = ['.cbranch-no', '.cstat-no', '.fstat-no'];

    // Elements to highlight in the file listing view
    var fileListingElements = ['td.pct.low'];

    // We don't want to select elements that are direct descendants of another match
    var notSelector = ':not(' + missingCoverageClasses.join('):not(') + ') > '; // becomes `:not(a):not(b) > `

    // Selector that finds elements on the page to which we can jump
    var selector =
        fileListingElements.join(', ') +
        ', ' +
        notSelector +
        missingCoverageClasses.join(', ' + notSelector); // becomes `:not(a):not(b) > a, :not(a):not(b) > b`

    // The NodeList of matching elements
    var missingCoverageElements = document.querySelectorAll(selector);

    var currentIndex;

    function toggleClass(index) {
        missingCoverageElements
            .item(currentIndex)
            .classList.remove('highlighted');
        missingCoverageElements.item(index).classList.add('highlighted');
    }

    function makeCurrent(index) {
        toggleClass(index);
        currentIndex = index;
        missingCoverageElements.item(index).scrollIntoView({
            behavior: 'smooth',
            block: 'center',
            inline: 'center'
        });
    }

    function goToPrevious() {
        var nextIndex = 0;
        if (typeof currentIndex !== 'number' || currentIndex === 0) {
            nextIndex = missingCoverageElements.length - 1;
        } else if (missingCoverageElements.length > 1) {
            nextIndex = currentIndex - 1;
        }

        makeCurrent(nextIndex);
    }

    function goToNext() {
        var nextIndex = 0;

        if (
            typeof currentIndex === 'number' &&
            currentIndex < missingCoverageElements.length - 1
        ) {
            nextIndex = currentIndex + 1;
        }

        makeCurrent(nextIndex);
    }

    return function jump(event) {
        if (
            document.getElementById('fileSearch') === document.activeElement &&
            document.activeElement != null
        ) {
            // if we're currently focused on the search input, we don't want to navigate
            return;
        }

        switch (event.which) {
            case 78: // n
            case 74: // j
                goToNext();
                break;
            case 66: // b
            case 75: // k
            case 80: // p
                goToPrevious();
                break;
        }
    };
})();
window.addEventListener('keydown', jumpToCode);

/**
 * @file lib/ai/componentGenerator.ts
 *
 * Core AI generation orchestrator.
 *
 * Enhancement: Now model-agnostic via:
 *  - modelRegistry   → capability profile per model
 *  - tieredPipeline  → pipeline config (temperature, tool rounds, token budget)
 *  - promptBuilder   → model-aware prompt (fill-in-blank / structured / freeform)
 *  - codeExtractor   → multi-strategy extraction (fence / heuristic / aggressive)
 *  - codeBeautifier  → deterministic post-processing (all models)
 *
 * All call sites are unchanged — function signature is identical.
 */

import { getWorkspaceAdapter } from './adapters/index';
import type { AdapterConfig } from './adapters/index';
import { resolveDefaultAdapter } from './resolveDefaultAdapter';
import { executeToolCalls } from './tools';
import { DEFAULT_AGENT_TOOLS } from './agentTools';

import { getRelevantExamples } from './memory';
import { buildSemanticContext } from './semanticKnowledgeBase';
import { type UIIntent, type DepthUIModePreset } from '../validation/schemas';
import { evaluateDepthExperience } from '../intelligence/depthEngine';
import { selectBlueprint, formatBlueprintForPrompt } from '../intelligence/blueprintEngine';
import { applyDesignRules, formatDesignRulesForPrompt } from '../intelligence/designRules';
import { validateGeneratedCode } from '../intelligence/codeValidator';
import { runRepairPipeline } from '../intelligence/repairPipeline';
import { repairGeneratedCode } from './uiReviewer';

// ── New: model-agnostic layer ─────────────────────────────────────────────────
import { getModelProfile, getCloudFallbackProfile } from './modelRegistry';
import { getPipelineConfig } from './tieredPipeline';
import { buildModelAwarePrompt, mergeSystemIntoUser } from './promptBuilder';
import { extractCode, isCompleteComponent } from './codeExtractor';
import { beautifyOutput } from '../intelligence/codeBeautifier';
import { enrichPromptWithFeedback } from './feedbackProcessor';
import { resolveStyleDNA, formatStyleDNAForPrompt } from '../intelligence/styleDNA';
import { buildUXStateContract } from '../intelligence/uxStateEngine';

export type GenerationMode = 'component' | 'app' | 'depth_ui';

export interface GenerationResult {
  success: boolean;
  code?: string;
  error?: string;
  blueprint?: ReturnType<typeof selectBlueprint>;
  validationWarnings?: string[];
  repairsApplied?: string[];
  /** Model tier used for this generation (for telemetry/debugging) */
  modelTier?: string;
  /** Beautifier transformations applied */
  beautifyTransformations?: string[];
  /** True when feedback history enriched the system prompt */
  feedbackEnriched?: boolean;
}

export async function generateComponent(
  intent: UIIntent,
  mode: GenerationMode = 'component',
  requestedModel: string = '',
  maxTokens: number = 5000,
  isMultiSlide: boolean = false,
  refinementContext?: { code: string; manifest?: unknown },
  /** Pass a pre-selected blueprint to skip automatic selection. */
  blueprintOverride?: ReturnType<typeof selectBlueprint>,
  workspaceId?: string,
  userId?: string,
  provider?: string,
  apiKey?: string,
  baseUrl?: string,
  thinkingPlan?: unknown,
): Promise<GenerationResult> {
  try {
    const searchText = intent.description + ' ' + intent.componentName;

    // ─── Step 0: UI Intelligence — Blueprint + Design Rules ─────────────────
    const blueprint = blueprintOverride || selectBlueprint(searchText);
    const designRules = applyDesignRules(searchText, blueprint.pageType);
    const blueprintContext = formatBlueprintForPrompt(blueprint);
    const designContext = formatDesignRulesForPrompt(designRules);
    // intelligenceContext is used by cloud/freeform paths that append to prompt
    const intelligenceContext = `${blueprintContext}\n\n${designContext}`;

    // ─── Step 1: Resolve model + credentials ─────────────────────────────────
    let cfg: AdapterConfig;
    if (requestedModel) {
      cfg = {
        model:   requestedModel,
        provider,
        apiKey:  apiKey && apiKey !== '••••' ? apiKey : undefined,
        baseUrl,
      };
    } else {
      cfg = resolveDefaultAdapter('GENERATION');
    }

    // ─── Step 2: Get model profile + pipeline config ──────────────────────────
    const effectiveModel = cfg.model;
    // Track whether the profile is EXPLICIT (registered) vs fallback.
    // Tools must never be passed to unregistered/unknown models — they may silently 400.
    const explicitProfile = getModelProfile(effectiveModel);
    const modelProfile = explicitProfile ?? getCloudFallbackProfile();
    const pipelineConfig = getPipelineConfig(modelProfile);

    // ─── Step 3: Knowledge + memory lookup ───────────────────────────────────
    // Phase 4: buildSemanticContext() runs all 5 sources in parallel:
    //  template | registry | blueprint | motion (depth_ui only) | feedback
    // Returns a single merged context block with graceful per-source fallbacks.
    let knowledge: string | null = null;
    const memory = await getRelevantExamples(intent);

    if (!intent.isRefinement) {
      const semanticContext = await buildSemanticContext(searchText, mode);
      knowledge = semanticContext || null;
    }

    // ─── Step 3.2: Depth UI Engine Evaluation ────────────────────────────────
    if (mode === 'depth_ui') {
      const depthSpec: DepthUIModePreset = evaluateDepthExperience(intent, blueprint);
      // Inject into intent so promptBuilder can see it
      (intent as UIIntent & { depthSpec?: DepthUIModePreset }).depthSpec = depthSpec;
    }

    // ─── Step 3.5: Feedback enrichment ───────────────────────────────────────
    // Reads the local stats cache (zero network) and injects corrective guidance
    // and/or approved example snippets into the system prompt when applicable.
    const feedbackEnrichment = await enrichPromptWithFeedback(intent, effectiveModel);

    // ─── Step 4: Build model-aware prompt ────────────────────────────────────
    let builtPrompt = buildModelAwarePrompt(
      intent,
      blueprint,
      pipelineConfig,
      mode,
      knowledge,
      memory,
      refinementContext,
    );

    // For cloud/freeform modes: append intelligence context to user prompt
    // (tiny/small models have the blueprint baked into their structured prompts)
    if (pipelineConfig.promptStyle === 'freeform' || pipelineConfig.promptStyle === 'guided-freeform') {
      builtPrompt = {
        system: builtPrompt.system,
        user: builtPrompt.user + '\n\n' + intelligenceContext,
      };
    }

    // Inject feedback enrichment into system prompt (after main prompt is built)
    if (feedbackEnrichment.systemPromptAppend) {
      builtPrompt = {
        ...builtPrompt,
        system: ((builtPrompt.system ?? '') + '\n\n' + feedbackEnrichment.systemPromptAppend).trimStart(),
      };
    }

    if (thinkingPlan) {
      const serializedPlan = JSON.stringify(thinkingPlan, null, 2);
      builtPrompt = {
        ...builtPrompt,
        system: (
          (builtPrompt.system ?? '') +
          '\n\nREASONING ALIGNMENT:\n' +
          'Follow this approved thinking plan while matching prior gold-standard fixes.\n' +
          serializedPlan
        ).trimStart(),
      };
    }

    // ─── Step 4.5: Style DNA + UX State Contract (component / depth_ui only) ──────
    // Injects a deterministic visual fingerprint and interaction-state contract
    // into the system prompt. Skip for app mode (has its own design system).
    if (mode === 'component' || mode === 'depth_ui') {
      const dna            = resolveStyleDNA(intent.description, blueprint.pageType, mode);
      const dnaBlock       = formatStyleDNAForPrompt(dna);
      const uxContract     = buildUXStateContract(intent.description) ?? '';

      const dnaAndContract = [dnaBlock, uxContract].filter(Boolean).join('\n\n');
      if (dnaAndContract) {
        builtPrompt = {
          ...builtPrompt,
          system: ((builtPrompt.system ?? '') + '\n\n' + dnaAndContract).trimStart(),
        };
      }
    }

    // If model doesn't honour system role: merge system into user message
    if (pipelineConfig.mergeSystemIntoUser) {
      builtPrompt = mergeSystemIntoUser(builtPrompt);
    }

    // ─── Step 5: Get adapter ─────────────────────────────────────────────────
    const adapter = await getWorkspaceAdapter(cfg, workspaceId, userId);

    // ─── Step 6: Agentic Tool Loop ───────────────────────────────────────────
    // Respects maxToolRounds from pipeline config (0 for tiny/small, up to 3 for cloud).
    //
    // OpenAI tool-call protocol (strict — violating causes 400 no-body):
    //   1. User sends messages + tools array
    //   2. Model responds with assistant message containing `tool_calls`
    //   3. Client must append:
    //       a. The assistant message WITH the raw tool_calls array intact
    //       b. One { role:'tool', tool_call_id, content } per call
    //   4. Client calls generate() again — model produces final text
    //
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const messages: any[] = builtPrompt.system
      ? [
          { role: 'system', content: builtPrompt.system },
          { role: 'user',   content: builtPrompt.user   },
        ]
      : [{ role: 'user', content: builtPrompt.user }];

    let rawContent = '';
    const maxToolRounds = pipelineConfig.maxToolRounds;

    // Only inject tools when the model has an explicit registry entry with supportsToolCalls:true.
    // Fallback/unknown models must NOT receive tools — they may silently reject them (400 no body).
    let toolsEnabled = explicitProfile !== null && maxToolRounds > 0;

    for (let round = 0; round <= maxToolRounds; round++) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      let result: any;
      try {
        result = await adapter.generate({
          model:       effectiveModel,
          messages,
          temperature: pipelineConfig.temperature,
          maxTokens:   Math.min(maxTokens || 5000, pipelineConfig.maxOutputTokens),
          ...(toolsEnabled && {
            tools:      DEFAULT_AGENT_TOOLS,
            toolChoice: 'auto' as const,
          }),
        });
      } catch (genErr: unknown) {
        const errMsg = genErr instanceof Error ? genErr.message : String(genErr);
        // If tools were injected and caused a 400, retry once without tools
        // then disable tools for all remaining rounds (self-healing fallback).
        if (toolsEnabled && errMsg.includes('400')) {
          console.warn(
            `[componentGenerator] Tool-call 400 on ${effectiveModel} (round ${round}). ` +
            'Retrying without tools and disabling for remaining rounds.'
          );
          toolsEnabled = false;
          result = await adapter.generate({
            model:       effectiveModel,
            messages,
            temperature: pipelineConfig.temperature,
            maxTokens:   Math.min(maxTokens || 5000, pipelineConfig.maxOutputTokens),
          });
        } else {
          throw genErr;
        }
      }

      if (toolsEnabled && result.toolCalls && result.toolCalls.length > 0 && round < maxToolRounds) {
        // 1. Append assistant message WITH the raw tool_calls array intact (protocol requirement).
        messages.push({
          role:       'assistant',
          content:    result.content || null,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          tool_calls: result.toolCalls.map((tc: any) => ({
            id:       tc.id,
            type:     'function',
            function: {
              name:      tc.name,
              arguments: JSON.stringify(tc.arguments ?? {}),
            },
          })),
        });

        // 2. Execute all requested tools in parallel
        const toolResults = await executeToolCalls(result.toolCalls, DEFAULT_AGENT_TOOLS);

        // 3. One role:'tool' message per call (NOT role:'user' — that causes 400)
        for (const tr of toolResults) {
          messages.push({
            role:         'tool',
            tool_call_id: tr.tool_call_id,
            content:      tr.content,
          });
        }

        continue;
      }

      // No tool calls — model produced final output
      rawContent = result.content;
      break;
    }

    // If all rounds exhausted without output
    if (!rawContent) {
      return { success: false, error: 'AI returned empty component code after all tool-call rounds', modelTier: modelProfile.tier };
    }

    // ─── Step 7: Extract code (model-aware strategy) ──────────────────────────
    const extraction = extractCode(rawContent, pipelineConfig.extractionStrategy);
    const cleaned = extraction.code;

    // Basic sanity check
    if (!cleaned || (!cleaned.includes('export') && !cleaned.includes('return'))) {
      return {
        success: false,
        error: `Generated code does not appear to be a valid React component (extraction confidence: ${extraction.confidence}). Output start: "${cleaned?.substring(0, 150) ?? '(empty)'}..."`,
        modelTier: modelProfile.tier,
      };
    }

    // Log low-confidence extractions for monitoring
    if (extraction.confidence === 'low') {
      // Non-blocking — just annotate in the result
    }

    // Check for completeness (missing closing braces / export)
    const complete = isCompleteComponent(cleaned);

    // ─── Step 8: Post-Generation Beautifier (all models) ─────────────────────
    const beautified = beautifyOutput(cleaned, blueprint);

    // ─── Step 9: Validate + Auto-Repair ──────────────────────────────────────
    const validation = validateGeneratedCode(beautified.code);
    let finalCode = beautified.code;
    let repairsApplied: string[] = [];
    const validationWarnings = validation.warnings.map((w) => w.message);

    if (!validation.valid) {
      // Determine repair capability:
      // - Cloud models and 'large' tier → rules-only (no LLM repair)
      // - Tiny/small with ai-cheap → use LLM repair
      const canUseAiRepair =
        pipelineConfig.repairStrategy === 'ai-cheap' ||
        pipelineConfig.repairStrategy === 'ai-strong';

      const repairResult = await runRepairPipeline(
        beautified.code,
        canUseAiRepair
          ? async (code: string, instructions: string) => repairGeneratedCode(code, instructions)
          : undefined,
      );
      finalCode = repairResult.code;
      repairsApplied = repairResult.repairsApplied;
    }

    // If component is incomplete (e.g. truncated by tiny model), note it
    if (!complete && !repairsApplied.length) {
      validationWarnings.push('Component may be incomplete — check closing tags and export');
    }

    return {
      success: true,
      code: finalCode,
      blueprint,
      validationWarnings,
      repairsApplied,
      modelTier: modelProfile.tier,
      beautifyTransformations: beautified.transformations,
      feedbackEnriched: !!feedbackEnrichment.systemPromptAppend,
    };
  } catch (error) {
    // Log the ORIGINAL error with its full stack here so Vercel logs show the real call site.
    // Without this, the stack is discarded and reqLogger.error(new Error(...)) in the route
    // creates a NEW Error whose stack points only at the logging call — not the actual throw.
    const originalStack = error instanceof Error ? error.stack : String(error);
    const msg           = error instanceof Error ? error.message : 'Unknown error';
    console.error('[componentGenerator] Fatal error — original stack:\n', originalStack);
    return { success: false, error: `AI generation error: ${msg}` };
  }
}

import { getWorkspaceAdapter } from './adapters/index';
import type { AdapterConfig } from './adapters/index';
import { resolveDefaultAdapter } from './resolveDefaultAdapter';
import { getModelProfile } from './modelRegistry';
import {
  INTENT_PARSER_SYSTEM_PROMPT,
  APP_MODE_INTENT_SYSTEM_PROMPT,
  DEPTH_UI_INTENT_SYSTEM_PROMPT,
  buildIntentParsePrompt,
  buildAppModeIntentPrompt,
  buildDepthUIModeIntentPrompt,
} from './prompts';
import {
  findRelevantKnowledgeSemantic,
  findAppTemplateSemantic,
  findDepthUITemplateSemantic,
  findRelevantFeedback,
} from './semanticKnowledgeBase';
import { 
  UIIntentSchema, 
  AppIntentSchema, 
  DepthUIIntentSchema, 
  type UIIntent 
} from '../validation/schemas';
import type { GenerationMode } from './componentGenerator';

// Dynamic client used inside the function.

export interface ParseResult {
  success: boolean;
  intent?: UIIntent;
  error?: string;
  rawResponse?: string;
}

export async function parseIntent(
  userInput: string,
  mode: GenerationMode = 'component',
  /** Link to persistent project if provided — enables refinement detection */
  contextId?: string,
  /**
   * Caller-supplied adapter config.
   * When provided, skips resolveDefaultAdapter entirely — the caller's model/provider/key are used.
   * When omitted, falls through to INTENT_MODEL env var → any provider env key → local Ollama.
   */
  modelConfig?: { model: string; provider?: string; apiKey?: string; baseUrl?: string },
): Promise<ParseResult> {
  if (!userInput || userInput.trim().length === 0) {
    return { success: false, error: 'Input cannot be empty' };
  }
  if (userInput.trim().length < 3) {
    return { success: false, error: 'Input too short — describe a UI component or app' };
  }
  try {
    let knowledge: string | null;
    let systemPrompt: string;
    let userPrompt: string;

    // ── Semantic knowledge retrieval (falls back to keyword matching internally) ──
    if (mode === 'depth_ui') {
      knowledge = await findDepthUITemplateSemantic(userInput) ?? await findRelevantKnowledgeSemantic(userInput);
      systemPrompt = DEPTH_UI_INTENT_SYSTEM_PROMPT;
      userPrompt = buildDepthUIModeIntentPrompt(userInput, knowledge);
    } else if (mode === 'app') {
      knowledge = await findAppTemplateSemantic(userInput) ?? await findRelevantKnowledgeSemantic(userInput);
      systemPrompt = APP_MODE_INTENT_SYSTEM_PROMPT;
      userPrompt = buildAppModeIntentPrompt(userInput, knowledge);
    } else {
      // Semantic component search + RAG from past user corrections
      const [semanticKnowledge, feedbackContext] = await Promise.all([
        findRelevantKnowledgeSemantic(userInput),
        findRelevantFeedback(userInput),
      ]);
      knowledge = [semanticKnowledge, feedbackContext].filter(Boolean).join('\n\n') || null;
      systemPrompt = INTENT_PARSER_SYSTEM_PROMPT;
      userPrompt = buildIntentParsePrompt(userInput, knowledge);
    }

    if (contextId) {
      userPrompt += `\n\n=== ITERATIVE CONTEXT ===\nThis request is a follow-up to project ID: ${contextId}. Determine if this is a refinement/modification and set "isRefinement" accordingly in your JSON response.`;
    }

    // Resolve model + credentials — priority order:
    //  1. Caller-supplied modelConfig (user's explicit UI selection — highest priority)
    //  2. resolveDefaultAdapter checks purpose env var → any provider env key → Ollama
    let cfg: AdapterConfig;
    if (modelConfig) {
      cfg = modelConfig;
    } else {
      cfg = resolveDefaultAdapter('INTENT');
    }

    const adapter = await getWorkspaceAdapter(cfg);

    // Look up model capacity — governs whether JSON mode is safe to enable.
    // Models like deepseek-coder report supportsJsonMode: false; we skip it for them.
    // Additionally, Ollama requires the word "json" in the system prompt when JSON mode is enabled.
    const modelProfile = getModelProfile(cfg.model);
    const useJsonMode = modelProfile?.supportsJsonMode !== false;

    // Ensure the system prompt contains the word "json" — required by Ollama when using JSON mode.
    // This is a no-op for cloud models that ignore it.
    const effectiveSystemPrompt = useJsonMode && !systemPrompt.toLowerCase().includes('json')
      ? `Respond with valid JSON only.\n\n${systemPrompt}`
      : systemPrompt;

    const adapterResult = await adapter.generate({
      model: cfg.model,
      messages: [
        { role: 'system', content: effectiveSystemPrompt },
        { role: 'user', content: userPrompt },
      ],
      ...(useJsonMode ? { responseFormat: 'json_object' as const } : {}),
      temperature: 0.2,
    });

    const rawContent = adapterResult.content;

    if (!rawContent) {
      return { success: false, error: 'AI returned empty response' };
    }

    // 1. Strip thinking blocks completely so they don't corrupt JSON parsing
    let noThinkBlock = rawContent.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

    // 2. Extract JSON if wrapped in markdown
    const jsonMatch = noThinkBlock.match(/```(?:json)?\s*([\s\S]*?)\s*```/);

    let cleanedRaw = noThinkBlock;
    if (jsonMatch) {
      cleanedRaw = jsonMatch[1].trim();
    } else {
      // 3. Fallback: walk forward from the first '{' counting bracket depth.
      //    lastIndexOf('}') is NOT safe — trailing text like "handles {screens}" would
      //    return the wrong closing brace and produce malformed JSON.
      const start = noThinkBlock.indexOf('{');
      if (start !== -1) {
        let depth = 0;
        let inString = false;
        let escape = false;
        let end = -1;
        for (let i = start; i < noThinkBlock.length; i++) {
          const ch = noThinkBlock[i];
          if (escape)             { escape = false; continue; }
          if (ch === '\\' && inString) { escape = true;  continue; }
          if (ch === '"')         { inString = !inString; continue; }
          if (inString)           continue;
          if (ch === '{')         depth++;
          else if (ch === '}') {
            depth--;
            if (depth === 0) { end = i; break; }
          }
        }
        if (end !== -1) cleanedRaw = noThinkBlock.substring(start, end + 1);
      }
    }

    let parsed: unknown;
    try {
      parsed = JSON.parse(cleanedRaw);
    } catch {
      return { success: false, error: 'AI returned malformed JSON', rawResponse: rawContent };
    }

    // Check for error response from AI
    if (typeof parsed === 'object' && parsed !== null && 'error' in parsed) {
      const aiErrorMsg = (parsed as { error: string }).error;

      // "Not a UI description" is a soft rejection — the model was too strict.
      // The prompt already passed input validation + classify, so we attempt a
      // minimal-intent recovery instead of hard-failing the whole pipeline.
      if (aiErrorMsg === 'Not a UI description' || aiErrorMsg?.toLowerCase().includes('not a ui')) {
        // Build a minimal fallback intent so generation can still proceed
        const fallbackIntent = {
          componentType: 'component',
          componentName: userInput.trim().split(' ').slice(0, 3).map(
            (w: string) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()
          ).join('') + 'Component',
          description: userInput.trim().substring(0, 200),
          fields: [],
          layout: { type: 'single-column', maxWidth: 'lg', alignment: 'center' },
          interactions: [],
          theme: { variant: 'default', size: 'md' },
          a11yRequired: ['keyboard navigation', 'aria-labels'],
          semanticElements: ['main', 'section'],
          isRefinement: false,
        };
        const fallbackValidation = (mode === 'app' ? AppIntentSchema : mode === 'depth_ui' ? DepthUIIntentSchema : UIIntentSchema).safeParse(fallbackIntent);
        if (fallbackValidation.success) {
          return { success: true, intent: fallbackValidation.data, rawResponse: rawContent };
        }
      }

      return {
        success: false,
        error: `AI rejected this prompt: ${aiErrorMsg}. Try rephrasing as a UI component description (e.g. "a login form", "a dashboard card", "a hero section").`,
        rawResponse: rawContent,
      };
    }

    // Select schema based on mode
    const schema = mode === 'app' ? AppIntentSchema : mode === 'depth_ui' ? DepthUIIntentSchema : UIIntentSchema;

    // Validate against Zod schema
    const validation = schema.safeParse(parsed);
    if (!validation.success) {
      return {
        success: false,
        error: `Schema validation failed: ${validation.error.issues.map((i: any) => i.message).join(', ')}`,
        rawResponse: rawContent,
      };
    }

    const validIntent = validation.data;
    if (validIntent.componentName) {
      validIntent.componentName = validIntent.componentName
        .split(/[^a-zA-Z0-9]+/)
        .map((word: string) => word.charAt(0).toUpperCase() + word.slice(1))
        .join('');
      if (!/^[a-zA-Z]/.test(validIntent.componentName)) {
        validIntent.componentName = 'C' + validIntent.componentName;
      }
    }

    return { success: true, intent: validIntent, rawResponse: rawContent };
  } catch (error) {
    const msg = error instanceof Error ? error.message : 'Unknown error';
    return { success: false, error: `Intent parser error: ${msg}` };
  }
}

/**
 * @file lib/ai/promptBuilder.ts
 *
 * Model-aware prompt construction.
 *
 * Returns the correct system + user prompt pair for any model tier.
 * The output of this module flows directly into adapter.generate().
 *
 * Prompt strategies:
 *
 * fill-in-blank (tiny)
 *   A near-complete TSX skeleton with {{TOKENS}} that the model fills.
 *   Locked imports are prepended. Temperature is 0.0.
 *   The model's job is pattern completion, not generation.
 *
 * structured-template (small)
 *   A numbered, step-by-step system prompt with a blueprint summary.
 *   Blueprint is truncated to the model's token budget.
 *   Explicit output format hint is included.
 *
 * guided-freeform (medium)
 *   Style guidelines + design rules. Blueprint in full but concise form.
 *   The model has creative freedom within constraints.
 *
 * freeform (large, cloud)
 *   The existing full system prompts from prompts.ts.
 *   No extra constraints — the model is trusted.
 */

import type { UIIntent } from '../validation/schemas';
import type { UIBlueprint } from '../intelligence/blueprintEngine';
import type { PipelineConfig } from './tieredPipeline';
import { truncateToTokenBudget } from './tieredPipeline';
import {
  COMPONENT_GENERATOR_SYSTEM_PROMPT,
  APP_MODE_SYSTEM_PROMPT,
  DEPTH_UI_SYSTEM_PROMPT,
  REFINEMENT_SYSTEM_PROMPT,
  buildComponentGeneratorPrompt,
  buildAppModeGeneratorPrompt,
  buildDepthUIModeGeneratorPrompt,
} from './prompts';
import { formatBlueprintForPrompt } from '../intelligence/blueprintEngine';
import type { MemoryEntry } from './memory';
import type { GenerationMode } from './componentGenerator';

// ─── Types ────────────────────────────────────────────────────────────────────

export interface BuiltPrompt {
  system: string;
  user: string;
}

// ─── Locked Import Block ──────────────────────────────────────────────────────

/**
 * Injected into tiny/small model prompts to prevent import hallucination.
 * These are the only imports the model is allowed to use.
 */
const LOCKED_IMPORTS = `import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Button, Card, Input, Modal } from '@ui/core';
import { Grid, Stack, Container } from '@ui/layout';
import { Icon } from '@ui/icons';
import { Motion } from '@ui/motion';
import { cn } from '@ui/utils/cn';

// TAILWIND AVAILABLE: bg-*, text-*, p-*, m-*, flex, grid, rounded-*, shadow-*, border-*, transition-*
// ALLOWED PACKAGES: @ui/core, @ui/layout, @ui/icons, @ui/motion, @ui/theming, @ui/typography,
//   @ui/charts, @ui/forms, @ui/a11y, @ui/dragdrop, @ui/editor, @ui/command-palette
//   lucide-react, framer-motion, recharts, react-router-dom
// DO NOT import packages not in the list above. They do not exist in the sandbox.`.trim();

// ─── Fill-in-Blank Template (tiny models) ────────────────────────────────────

const FILL_IN_BLANK_SYSTEM = `You are a code completion machine. You complete code templates.
RULES (non-negotiable):
1. Output ONLY valid TSX code. No explanation. No markdown.
2. Do NOT add any imports — imports are already provided.
3. Do NOT change the export structure.
4. Fill in ONLY the marked TODO sections.
5. Keep Tailwind classes. Do NOT invent spacing values like p-[13px].
6. Every JSX tag you open MUST be closed.`;

function buildFillInBlankPrompt(
  intent: UIIntent,
  blueprint: UIBlueprint,
  _config: PipelineConfig,
): BuiltPrompt {
  const componentName = intent.componentName || 'GeneratedComponent';
  const description = intent.description || 'A React component';

  // Derive structural sections and visual style from blueprint (truncated)
  const sections = blueprint.structuralSections.slice(0, 3);
  const visualStyle = blueprint.visualStyle;
  const requiredComponents = blueprint.requiredComponents.slice(0, 3);

  // Map visual style to tailwind class hints
  const styleHints: Record<string, string> = {
    glassmorphism: 'backdrop-blur-xl bg-white/10 border border-white/20',
    'premium-dark': 'bg-gray-900 text-white',
    minimal: 'bg-white text-gray-900',
    futuristic: 'bg-black text-cyan-400 border border-cyan-800',
    luxury: 'bg-gradient-to-br from-amber-900 to-stone-900 text-amber-100',
    animated: 'bg-white text-gray-900',
    cyberpunk: 'bg-black text-yellow-400 border border-yellow-600',
    'bento-grid': 'grid grid-cols-2 gap-4 bg-gray-100',
  };

  const containerClass = styleHints[visualStyle] ?? 'bg-white text-gray-900';

  const skeleton = `${LOCKED_IMPORTS}

interface ${componentName}Props {
  // TODO: Add 2-3 relevant props for a ${description}
}

export default function ${componentName}({ }: ${componentName}Props) {
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // TODO: Simulate data loading (use setTimeout, 1000ms)
  }, []);

  return (
    <div className="${containerClass} p-6 rounded-xl" role="main" aria-label="${description}">
      {/* SECTION: ${sections[0] ?? 'Header'} */}
      <header className="mb-6">
        {/* TODO: Render the ${sections[0] ?? 'header'} content */}
        {/* Use at least one of: ${requiredComponents.join(', ')} */}
      </header>

      {/* SECTION: ${sections[1] ?? 'Main Content'} */}
      <main className="flex flex-col gap-4">
        {/* TODO: Render the ${sections[1] ?? 'main content'} */}
      </main>

      {/* SECTION: ${sections[2] ?? 'Footer'} */}
      <footer className="mt-8 pt-4 border-t border-current/10">
        {/* TODO: Render the ${sections[2] ?? 'footer'} content */}
      </footer>
    </div>
  );
}`;

  return {
    system: FILL_IN_BLANK_SYSTEM,
    user: `Complete this React component. Fill ONLY the TODO sections.\n\nComponent purpose: ${description}\n\n\`\`\`tsx\n${skeleton}\n\`\`\``,
  };
}

// ─── Structured Template (small models) ──────────────────────────────────────

function buildStructuredPrompt(
  intent: UIIntent,
  blueprint: UIBlueprint,
  config: PipelineConfig,
  knowledge: string | null,
): BuiltPrompt {
  const blueprintText = truncateToTokenBudget(
    formatBlueprintForPrompt(blueprint),
    config.blueprintTokenBudget,
  );

  const system = `You are a React/TypeScript developer. Follow these steps to generate a component:

STEP 1 — Read the blueprint below carefully.
STEP 2 — Use ONLY these imports:
${LOCKED_IMPORTS}

STEP 3 — Generate a complete, valid TSX component.

MANDATORY RULES:
- Output ONLY raw TSX code. No markdown fences. No explanation.
- Export default the main component.
- Use Tailwind CSS for all styling.
- Add aria-label to interactive elements.
- Close every JSX tag you open.
- Use only valid Tailwind spacing: p-4, m-2, gap-6 (NOT p-[13px]).

${blueprintText}`;

  const requiredComp = intent.componentName || 'GeneratedComponent';
  let user = `Build a React TypeScript component: "${requiredComp}"\n\nDescription: ${intent.description}\n\nRequired sections: ${blueprint.structuralSections.join(', ')}\n\nMust include these components: ${blueprint.requiredComponents.slice(0, 3).join(', ')}`;

  if (knowledge) {
    user += `\n\nKNOWLEDGE BASE:\n${knowledge.substring(0, 800)}`;
  }

  return { system, user };
}

// ─── Guided Freeform (medium models) ─────────────────────────────────────────

function buildGuidedFreeformPrompt(
  intent: UIIntent,
  blueprint: UIBlueprint,
  config: PipelineConfig,
  knowledge: string | null,
  memory: MemoryEntry[],
): BuiltPrompt {
  const blueprintText = truncateToTokenBudget(
    formatBlueprintForPrompt(blueprint),
    config.blueprintTokenBudget,
  );

  const system = `You are an expert React/TypeScript developer specialising in accessible, modern UI components.

DESIGN GUIDELINES:
- Visual style: ${blueprint.visualStyle}
- Animation level: ${blueprint.animationDensity}
- Responsive: mobile-first with Tailwind sm: md: lg: xl: prefixes
- Accessibility: WCAG 2.1 AA — all interactive elements need aria-labels, semantic HTML
- Tailwind spacing scale: use only standard values (p-4, m-2, gap-6 — NOT p-[13px])

UI ECOSYSTEM IMPORTS (preferred):
- \`import { Button, Card, Input, Modal } from '@ui/core';\`
- \`import { Grid, Stack, Container } from '@ui/layout';\`
- \`import { Icon } from '@ui/icons';\`
- \`import { Motion } from '@ui/motion';\`

${blueprintText}

OUTPUT: Return ONLY raw TSX code. No markdown. No explanation. Export default the main component.`;

  const userPrompt = buildComponentGeneratorPrompt(intent, knowledge, memory, false);

  return { system, user: userPrompt };
}

// ─── Public Entry Point ───────────────────────────────────────────────────────

/**
 * Build the final system + user prompt for code generation.
 *
 * Routes to the appropriate strategy based on the pipeline config.
 * Cloud/large models use the existing full prompt builders from prompts.ts.
 *
 * @param intent    Parsed UI intent
 * @param blueprint Selected UI blueprint from blueprintEngine
 * @param config    Pipeline config derived from the model's capability profile
 * @param mode      Generation mode: 'component' | 'app' | 'depth_ui'
 * @param knowledge Optional knowledge base injection (pattern examples)
 * @param memory    Optional few-shot examples from memory store
 * @param refinementContext  If set, this is a refinement request
 */
export function buildModelAwarePrompt(
  intent: UIIntent,
  blueprint: UIBlueprint,
  config: PipelineConfig,
  mode: GenerationMode,
  knowledge: string | null = null,
  memory: MemoryEntry[] = [],
  refinementContext?: { code: string; manifest?: unknown },
): BuiltPrompt {
  // ── Refinement always uses full freeform regardless of model tier ──────────
  if (intent.isRefinement && refinementContext) {
    return {
      system: REFINEMENT_SYSTEM_PROMPT,
      user:
        `TARGET FILE CODE:\n${refinementContext.code}\n\n` +
        `APP MANIFEST:\n${JSON.stringify(refinementContext.manifest || [], null, 2)}\n\n` +
        `REFINEMENT INTENT:\n${JSON.stringify(intent, null, 2)}`,
    };
  }

  // ── Dispatch by prompt strategy ───────────────────────────────────────────
  switch (config.promptStyle) {
    case 'fill-in-blank':
      // Tiny models — fill-in-blank skeleton (mode is always 'component' for tiny)
      return buildFillInBlankPrompt(intent, blueprint, config);

    case 'structured-template':
      // Small models — structured numbered steps
      return buildStructuredPrompt(intent, blueprint, config, knowledge);

    case 'guided-freeform':
      // Medium models — style guidelines + design rules
      return buildGuidedFreeformPrompt(intent, blueprint, config, knowledge, memory);

    case 'freeform':
    default:
      // Large and cloud models — full existing system prompts
      if (mode === 'depth_ui') {
        return {
          system: DEPTH_UI_SYSTEM_PROMPT,
          user: buildDepthUIModeGeneratorPrompt(intent, knowledge, false),
        };
      }
      if (mode === 'app') {
        return {
          system: APP_MODE_SYSTEM_PROMPT,
          user: buildAppModeGeneratorPrompt(intent, knowledge, memory, false),
        };
      }
      return {
        system: COMPONENT_GENERATOR_SYSTEM_PROMPT,
        user: buildComponentGeneratorPrompt(intent, knowledge, memory, false),
      };
  }
}

/**
 * If the model does not honour the system role (mergeSystemIntoUser: true),
 * collapse system + user into a single user message.
 *
 * Usage: call this AFTER buildModelAwarePrompt() when config.mergeSystemIntoUser is true.
 */
export function mergeSystemIntoUser(prompt: BuiltPrompt): BuiltPrompt {
  return {
    system: '',
    user: `${prompt.system}\n\n---\n\n${prompt.user}`,
  };
}

/**
 * @file lib/intelligence/codeBeautifier.ts
 *
 * Deterministic post-generation beautifier.
 *
 * Runs on ALL generated code regardless of model tier.
 * Makes every model's output consistent by applying a set of
 * format-only, logic-preserving transformations.
 *
 * Design rules:
 *  1. NEVER change business logic — only format, structure, and annotations
 *  2. NEVER call an LLM — this is 100% deterministic and instant
 *  3. When in doubt, skip the transformation (false negatives > false positives)
 *  4. Every transformation must be reversible in principle
 *
 * Transformations applied (in order):
 *  1. Strip debug console.log / console.warn statements
 *  2. Sort and normalise import blocks
 *  3. Add missing aria-label to interactive elements (heuristic)
 *  4. Replace <div onClick> with <button> (semantic HTML)
 *  5. Add missing key props to JSX map() renders
 *  6. Normalise className to use cn() when conditional
 *  7. Ensure at least one responsive Tailwind prefix exists (sm: fallback)
 */

import type { UIBlueprint } from './blueprintEngine';

// ─── Result Type ──────────────────────────────────────────────────────────────

export interface BeautifyResult {
  code: string;
  /** Human-readable log of every transformation applied */
  transformations: string[];
}

// ─── Individual Transformations ───────────────────────────────────────────────

type Transform = (code: string, transformations: string[]) => string;

// 1. Strip debug console statements from production code
const stripDebugConsole: Transform = (code, log) => {
  const before = code;
  const result = code
    .replace(/^\s*console\.(log|warn|error|debug|info)\([^)]*\);?\s*\n?/gm, '')
    // Also handle multi-line console calls (up to 3 lines)
    .replace(/console\.(log|warn|debug)\(\s*[\s\S]{0,200}?\);/g, '/* [debug removed] */');
  if (result !== before) log.push('Stripped debug console statements');
  return result;
};

// 2. Sort import blocks into consistent order
// Order: react → @ui/* → external → relative (@/, ../)
const sortImports: Transform = (code, log) => {
  const lines = code.split('\n');
  const importBlock: string[] = [];
  let importEnd = 0;

  // Collect all import lines from the top of the file
  for (let i = 0; i < lines.length; i++) {
    const trimmed = lines[i].trim();
    if (trimmed.startsWith('import ') || (importBlock.length > 0 && trimmed === '')) {
      if (trimmed.startsWith('import ')) {
        importBlock.push(lines[i]);
        importEnd = i + 1;
      } else if (importBlock.length > 0 && trimmed === '') {
        importEnd = i; // stop at first blank line after imports
        break;
      }
    } else if (importBlock.length > 0) {
      importEnd = i;
      break;
    }
  }

  if (importBlock.length < 2) return code; // nothing to sort

  const priority = (line: string): number => {
    if (/from ['"]react['"]/i.test(line)) return 0;
    if (/from ['"]@ui\//i.test(line)) return 1;
    if (/from ['"]@react-three\//i.test(line)) return 2;
    if (/from ['"]@\//.test(line)) return 3;
    if (/from ['"]\.\./i.test(line)) return 4;
    if (/from ['"]\./i.test(line)) return 5;
    return 2; // external packages
  };

  const sorted = [...importBlock].sort((a, b) => priority(a) - priority(b));
  const identical = sorted.every((l, i) => l === importBlock[i]);
  if (identical) return code;

  const rest = lines.slice(importEnd);
  log.push('Sorted import block by dependency layer');
  return [...sorted, ...rest].join('\n');
};

// 3. Add missing aria-label to <button> elements that have no text or aria attributes
const addMissingAriaLabels: Transform = (code, log) => {
  let changed = false;

  // Match <button className="..."> or <button> without any aria- or children text hint
  const result = code.replace(
    /<button(\s[^>]*)?>/g,
    (match) => {
      // Skip if already has aria attributes
      if (/aria-/.test(match)) return match;
      // Skip if it has a type='submit' or type='button' with visible text nearby (too complex to detect safely)
      // Only add aria-label if it's an icon-only button pattern (very short)
      if (match.length > 120) return match;
      changed = true;
      return match.replace(/<button/, '<button aria-label="Action button"');
    }
  );

  if (changed) log.push('Added aria-label to icon-only button elements');
  return result;
};

// 4. Replace <div onClick> with <button> where the div has no children role
const fixSemanticHTML: Transform = (code, log) => {
  // Only replace simple cases: <div onClick={...}> with no existing role
  const before = code;

  const result = code.replace(
    /<div(\s+className="[^"]*")?\s+onClick=\{([^}]+)\}(\s+className="[^"]*")?>/g,
    (match, cls1, handler, cls2) => {
      // Skip if it already has a role= attribute
      if (/role=/.test(match)) return match;
      // Skip if the handler is complex (> 60 chars)
      if (handler && handler.length > 60) return match;
      const className = cls1 ?? cls2 ?? '';
      return `<button${className} onClick={${handler}} type="button">`;
    }
  );

  if (result !== before) log.push('Replaced <div onClick> with <button> for semantic HTML');
  return result;
};

// 5. Add missing key props to array.map() JSX renders
const addMissingKeyProps: Transform = (code, log) => {
  let changed = false;

  // Match patterns like: items.map((item) => <SomeComponent or <div without key
  const result = code.replace(
    /\.map\(\s*\((\w+)(?:,\s*(\w+))?\)\s*=>\s*(<(?!\/)[A-Za-z][A-Za-z0-9]*(?!\s+key=)[^>]*?>)/g,
    (match, itemVar, indexVar, openTag) => {
      // Skip if key is already present
      if (/\bkey=/.test(openTag)) return match;
      changed = true;
      const keyExpr = indexVar || `${itemVar}?.id ?? index`;
      // Insert key={} after the opening tag name
      return match.replace(openTag, openTag.replace(/(<[A-Za-z][A-Za-z0-9]*)/, `$1 key={${keyExpr}}`));
    }
  );

  if (changed) log.push('Added missing key props to array.map() renders');
  return result;
};

// 6. Warn about arbitrary Tailwind values (p-[13px]) — replace with nearest valid scale
// This is advisory only — we log it but don't break the code
const flagArbitraryTailwind: Transform = (code, log) => {
  const arbitraryPattern = /\b(?:p|m|px|py|pt|pb|pl|pr|mt|mb|ml|mr|mx|my|gap|space-[xy])-\[\d+px\]/g;
  const matches = code.match(arbitraryPattern);
  if (matches && matches.length > 0) {
    const unique = [...new Set(matches)];
    log.push(`Advisory: Found arbitrary Tailwind values (${unique.slice(0, 3).join(', ')}${unique.length > 3 ? '...' : ''}) — consider replacing with scale values`);
  }
  return code; // don't modify — too risky to auto-replace
};

// 7. Ensure the component has at least one responsive prefix
const ensureResponsivePrefix: Transform = (code, log) => {
  // Only add advisory — modifying className logic is too risk-prone
  const hasResponsive = /\b(?:sm|md|lg|xl|2xl):/i.test(code);
  if (!hasResponsive && code.includes('className=')) {
    log.push('Advisory: No responsive Tailwind prefixes (sm: md: lg:) found — consider adding responsive breakpoints');
  }
  return code;
};

// 8. Remove duplicate blank lines (more than 2 consecutive)
const normaliseBlankLines: Transform = (code, log) => {
  const before = code;
  const result = code.replace(/\n{4,}/g, '\n\n\n');
  if (result !== before) log.push('Normalised excessive blank lines');
  return result;
};

// ─── Transformation Pipeline ───────────────────────────────────────────────────

const TRANSFORMS: Transform[] = [
  stripDebugConsole,
  sortImports,
  addMissingAriaLabels,
  fixSemanticHTML,
  addMissingKeyProps,
  flagArbitraryTailwind,
  ensureResponsivePrefix,
  normaliseBlankLines,
];

// ─── Public Entry Point ───────────────────────────────────────────────────────

/**
 * Apply the full beautifier pipeline to generated code.
 *
 * Safe to call on any model output — all transforms are logic-preserving.
 * Returns the processed code and a log of applied transformations.
 *
 * @param code      Raw extracted code from any model
 * @param blueprint The blueprint used for this generation (used for context)
 */
export function beautifyOutput(code: string, _blueprint?: UIBlueprint): BeautifyResult {
  if (!code || code.trim().length === 0) {
    return { code: '', transformations: [] };
  }

  const transformations: string[] = [];
  let result = code;

  for (const transform of TRANSFORMS) {
    try {
      result = transform(result, transformations);
    } catch {
      // Never let a beautifier transform crash the pipeline
      // The worst case is we skip the transform silently
    }
  }

  return { code: result.trim(), transformations };
}

import type { UIIntent } from './validation/schemas';

interface GeneratedTests {
  rtl: string;
  playwright: string;
}

export function generateTests(intent: UIIntent, _componentCode: string): GeneratedTests {
  const { componentName, fields, interactions, componentType } = intent;

  const rtl = generateRTLTests(componentName, fields, interactions);
  const playwright = generatePlaywrightTests(componentName, fields, interactions, componentType);

  return { rtl, playwright };
}

function generateRTLTests(
  componentName: string,
  fields: UIIntent['fields'],
  interactions: UIIntent['interactions'],
): string {
  const inputFields = fields.filter(f => ['text', 'email', 'password', 'textarea', 'number', 'tel'].includes(f.type));
  const buttonFields = fields.filter(f => f.type === 'button');
  const selectFields = fields.filter(f => f.type === 'select');
  const requiredFields = fields.filter(f => f.required);

  const interactionTests = interactions.map((interaction, i) => {
    if (interaction.trigger === 'submit') {
      return `
  it('handles form submission', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    ${inputFields.slice(0, 2).map(f =>
      `await user.type(screen.getByLabelText('${f.label}'), 'test-value');`
    ).join('\n    ')}
    const submitButton = screen.getByRole('button', { name: /submit/i });
    await user.click(submitButton);
    // Verify feedback state
    expect(submitButton).not.toBeDisabled();
  });`;
    }
    if (interaction.trigger === 'click') {
      return `
  it('handles click interaction ${i + 1}', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    // Test click interaction: ${interaction.action}
  });`;
    }
    return '';
  }).filter(Boolean);

  const validationTests = requiredFields.length > 0 ? `
  it('shows validation errors for required fields when empty', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    const submitButton = screen.getByRole('button', { name: /submit/i });
    await user.click(submitButton);
    ${requiredFields.slice(0, 2).map(() =>
      `expect(screen.queryByText(/required/i) || screen.queryByRole('alert')).toBeInTheDocument();`
    ).join('\n    ')}
  });` : '';

  const inputInteractionTests = inputFields.slice(0, 3).map(f => `
  it('allows typing in ${f.label} field', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    const input = screen.getByLabelText('${f.label}');
    await user.type(input, 'test input value');
    expect(input).toHaveValue('test input value');
  });`).join('');

  const selectInteractionTests = selectFields.slice(0, 2).map(f => `
  it('allows selecting option in ${f.label}', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    const select = screen.getByLabelText('${f.label}');
    ${f.options.length > 0 ? `await user.selectOptions(select, '${f.options[0]}');
    expect(select).toHaveValue('${f.options[0]}');` : '// No options defined'}
  });`).join('');

  const buttonTests = buttonFields.slice(0, 2).map(f => `
  it('renders ${f.label} button', () => {
    render(<${componentName} />);
    expect(screen.getByRole('button', { name: /${f.label}/i })).toBeInTheDocument();
  });`).join('');

  return `/**
 * Auto-generated React Testing Library tests
 * Component: ${componentName}
 * Generated by AI-Powered Accessibility-First UI Engine
 */

import React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import ${componentName} from '../components/${componentName}';

describe('${componentName}', () => {
  // ─── Render Tests ──────────────────────────────────────────────────────────

  it('renders without crashing', () => {
    render(<${componentName} />);
    expect(document.body).toBeInTheDocument();
  });

${fields.slice(0, 4).map(f => `  it('renders ${f.label}', () => {
    render(<${componentName} />);
    expect(screen.getByText('${f.label}')).toBeInTheDocument();
  });`).join('\n\n')}

  // ─── Interaction Tests ─────────────────────────────────────────────────────
${inputInteractionTests}
${selectInteractionTests}
${buttonTests}
${interactionTests.join('')}
${validationTests}

  // ─── Accessibility Tests ───────────────────────────────────────────────────

  it('has no heading structure violations', () => {
    render(<${componentName} />);
    // All headings should be findable by role
    const headings = screen.queryAllByRole('heading');
    headings.forEach(heading => {
      expect(heading).toBeVisible();
    });
  });

  it('all interactive elements are keyboard accessible', () => {
    render(<${componentName} />);
    const buttons = screen.queryAllByRole('button');
    buttons.forEach(button => {
      expect(button).not.toHaveAttribute('tabindex', '-1');
    });
  });

  it('form inputs have associated labels', () => {
    render(<${componentName} />);
    const inputs = document.querySelectorAll('input, textarea, select');
    inputs.forEach(input => {
      const id = input.getAttribute('id');
      if (id) {
        const label = document.querySelector(\`label[for="\${id}"]\`);
        const ariaLabel = input.getAttribute('aria-label');
        expect(label || ariaLabel).toBeTruthy();
      }
    });
  });

  it('buttons have accessible names', () => {
    render(<${componentName} />);
    const buttons = screen.queryAllByRole('button');
    buttons.forEach(button => {
      expect(button).toHaveAccessibleName();
    });
  });
});
`;
}

function generatePlaywrightTests(
  componentName: string,
  fields: UIIntent['fields'],
  _interactions: UIIntent['interactions'],
  componentType: string,
): string {
  const inputFields = fields.filter(f => ['text', 'email', 'password', 'textarea'].includes(f.type));
  const requiredFields = fields.filter(f => f.required);

  const fillFormSteps = inputFields.slice(0, 3).map(f => {
    if (f.type === 'password') return `  await page.fill('input#${f.id}', 'SecurePass123!');`;
    if (f.type === 'email') return `  await page.fill('input#${f.id}', 'test@example.com');`;
    return `  await page.fill('input#${f.id}, textarea#${f.id}', 'Test Value');`;
  }).join('\n');

  return `/**
 * Auto-generated Playwright E2E tests
 * Component: ${componentName} (${componentType})
 * Generated by AI-Powered Accessibility-First UI Engine
 * 
 * Prerequisites: Run 'npx playwright install' before running these tests.
 * Update BASE_URL to point to your running application.
 */

import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';

test.describe('${componentName} E2E Tests', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto(BASE_URL);
  });

  // ─── Visual Tests ──────────────────────────────────────────────────────────

  test('page loads and component is visible', async ({ page }) => {
    await expect(page).toHaveTitle(/.+/);
    await expect(page.locator('body')).toBeVisible();
  });

  // ─── Keyboard Navigation Tests ─────────────────────────────────────────────

  test('all interactive elements are reachable by Tab', async ({ page }) => {
    await page.keyboard.press('Tab');
    const focusedElement = await page.evaluate(() => document.activeElement?.tagName);
    expect(['INPUT', 'BUTTON', 'SELECT', 'TEXTAREA', 'A']).toContain(focusedElement);
  });

  test('form can be submitted via keyboard', async ({ page }) => {
${fillFormSteps}
    await page.keyboard.press('Tab'); // Move to submit
    await page.keyboard.press('Enter');
    // Verify some feedback
    await expect(page.locator('body')).toBeVisible();
  });

  // ─── Accessibility Tests ───────────────────────────────────────────────────

  test('no accessibility violations (axe-core)', async ({ page }) => {
    // Install: npm install --save-dev @axe-core/playwright
    // import { checkA11y } from '@axe-core/playwright';
    // await checkA11y(page);
    // Placeholder: manual ARIA check
    const buttons = await page.locator('button').all();
    for (const button of buttons) {
      const name = await button.getAttribute('aria-label') || await button.textContent();
      expect(name?.trim()).toBeTruthy();
    }
  });

  test('focus indicators are visible', async ({ page }) => {
    await page.keyboard.press('Tab');
    const focusedEl = page.locator(':focus');
    await expect(focusedEl).toBeVisible();
  });

${requiredFields.length > 0 ? `  // ─── Validation Tests ──────────────────────────────────────────────────────

  test('shows errors when required fields are empty', async ({ page }) => {
    const submitButton = page.locator('button[type="submit"]').first();
    if (await submitButton.count() > 0) {
      await submitButton.click();
      // Verify error messages appear
      const errors = page.locator('[role="alert"], .text-red-500, [aria-live="polite"]');
      // Errors may or may not appear depending on implementation
      await expect(page.locator('body')).toBeVisible();
    }
  });` : ''}

  // ─── Mobile Viewport Tests ─────────────────────────────────────────────────

  test('component is responsive on mobile', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 812 });
    await expect(page.locator('body')).toBeVisible();
    // Ensure no horizontal scroll
    const scrollWidth = await page.evaluate(() => document.documentElement.scrollWidth);
    const clientWidth = await page.evaluate(() => document.documentElement.clientWidth);
    expect(scrollWidth).toBeLessThanOrEqual(clientWidth + 5); // 5px tolerance
  });
});
`;
}

