'use client';

/**
 * @file packages/motion/components/Motion.tsx
 *
 * Phase 8 upgrade — framer-motion wrapper spec for the @ui/motion package.
 *
 * DESIGN CONTRACT:
 *  This package serves two audiences:
 *  1. TypeScript host build — needs to compile without framer-motion installed.
 *     Achieved by using a fallback CSS-based implementation as the default export.
 *  2. Sandpack preview runtime — has framer-motion available via the virtual
 *     dependency list. AI-generated code importing from 'framer-motion' directly
 *     WILL have the real library available.
 *
 * PRACTICAL IMPLICATION FOR AI-GENERATED CODE:
 *  The system prompt instructs models to import framer-motion directly:
 *    import { motion, useScroll, useTransform, useReducedMotion } from 'framer-motion'
 *  This is the CORRECT pattern for depth_ui mode. Do NOT tell models to import
 *  from '@ui/motion' for physics/scroll — that route is for component mode only.
 *
 * WHAT THIS FILE PROVIDES:
 *  - Motion       — viewport-reveal wrapper (fade/slide/scale/reveal/pop)
 *  - MotionGroup  — staggered children wrapper
 *  - AnimatePresence re-export stub
 *
 * GPU compositing, parallax coefficients, and useReducedMotion patterns are
 * injected into depth_ui system prompts directly (prompts.ts Phase 8).
 *
 * WCAG 2.1 SC 2.3.3 (AAA) compliance:
 *  - All animations check prefers-reduced-motion via the CSS @media query.
 *  - Framer-motion's useReducedMotion() is the recommended pattern in generated code.
 */

import React, { useEffect, useRef, useState } from 'react';

// ─── AnimatePresence stub (real in Sandpack, no-op shim in host) ──────────────

export function AnimatePresence({
  children,
}: {
  children: React.ReactNode;
  mode?: string;
  initial?: boolean;
}) {
  return <>{children}</>;
}

// ─── Reduced motion detection ─────────────────────────────────────────────────

function useSystemReducedMotion(): boolean {
  const [reduced, setReduced] = useState(false);
  useEffect(() => {
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReduced(mq.matches);
    const handler = (e: MediaQueryListEvent) => setReduced(e.matches);
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);
  return reduced;
}

// ─── Animation presets (CSS-based for host; framer-motion used in Sandpack) ──

type AnimationPreset = 'fade' | 'slide' | 'slide-left' | 'slide-right' | 'scale' | 'reveal' | 'pop' | 'parallax' | string;

const ANIMATION_CLASSES: Record<string, string> = {
  fade:        'opacity-0 motion-safe:animate-[fadeIn_0.5s_ease-out_forwards]',
  slide:       'opacity-0 translate-y-6 motion-safe:animate-[slideUp_0.5s_cubic-bezier(0.25,0.46,0.45,0.94)_forwards]',
  'slide-left' : 'opacity-0 -translate-x-8 motion-safe:animate-[slideRight_0.5s_ease-out_forwards]',
  'slide-right': 'opacity-0 translate-x-8  motion-safe:animate-[slideLeft_0.5s_ease-out_forwards]',
  scale:       'opacity-0 scale-95 motion-safe:animate-[scaleIn_0.45s_cubic-bezier(0.34,1.56,0.64,1)_forwards]',
  reveal:      'opacity-0 translate-y-4 blur-sm motion-safe:animate-[reveal_0.6s_ease-out_forwards]',
  pop:         'opacity-0 scale-80 motion-safe:animate-[popIn_0.4s_cubic-bezier(0.34,1.56,0.64,1)_forwards]',
  parallax:    '', // pass-through — no CSS parallax; note in docs that framer-motion is needed
};

// ─── Motion component props ───────────────────────────────────────────────────

export interface MotionProps_Custom {
  children:    React.ReactNode;
  /**
   * Named animation preset.
   * 'fade' | 'slide' | 'slide-left' | 'slide-right' | 'scale' | 'reveal' | 'pop' | 'parallax'
   * Default: 'fade'
   *
   * NOTE on 'parallax': In depth_ui mode, prefer importing useScroll/useTransform
   * directly from 'framer-motion' rather than using this wrapper. See prompts.ts.
   */
  animation?:  AnimationPreset;
  /** Delay before animation starts (seconds → converted to ms). Default: 0 */
  delay?:      number;
  /** Animation duration (seconds → converted to ms). Default: variant duration. */
  duration?:   number;
  /**
   * Viewport threshold for the IntersectionObserver [0–1].
   * Default: 0.15 — triggers when 15% of the element is visible.
   */
  threshold?:  number;
  /**
   * For 'parallax' animation: fraction of scroll speed (0–1). Default: 0.30.
   * In host build this is a no-op; use framer-motion directly in Sandpack.
   */
  speedFactor?: number;
  /** Additional class names applied to the wrapper element. */
  className?:  string;
  /** Whether to animate only once when first entering viewport. Default: true */
  once?:       boolean;
}

// ─── Main Motion component ────────────────────────────────────────────────────

/**
 * Universal viewport-reveal animation wrapper.
 *
 * Respects prefers-reduced-motion — reduced-motion users see elements
 * immediately without transitions.
 *
 * For GPU-compositable parallax (depth_ui mode), use framer-motion directly:
 *   const { scrollYProgress } = useScroll({ target: ref, offset: ['start end', 'end start'] });
 *   const y = useTransform(scrollYProgress, [0, 1], ['0px', '-90px']);
 */
export function Motion({
  children,
  animation  = 'fade',
  delay      = 0,
  duration,
  threshold  = 0.15,
  className  = '',
  once       = true,
}: MotionProps_Custom) {
  const shouldReduceMotion = useSystemReducedMotion();
  const ref     = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          if (once) obs.disconnect();
        } else if (!once) {
          setVisible(false);
        }
      },
      { threshold },
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold, once]);

  // Reduced-motion: show immediately with no class-based transition
  if (shouldReduceMotion) {
    return <div ref={ref} className={className}>{children}</div>;
  }

  const animClass = ANIMATION_CLASSES[animation] ?? ANIMATION_CLASSES.fade;

  const style: React.CSSProperties = {
    ...(delay    > 0  ? { animationDelay:    `${delay * 1000}ms`    } : {}),
    ...(duration != null ? { animationDuration: `${duration * 1000}ms` } : {}),
    // GPU compositing hint for all animated elements (TAF Dimension 14)
    willChange: visible ? 'auto' : 'opacity, transform',
  };

  return (
    <div
      ref={ref}
      style={style}
      className={`${visible ? animClass : 'opacity-0'} ${className}`}
    >
      {children}
    </div>
  );
}

// ─── MotionGroup — staggered children ────────────────────────────────────────

export interface MotionGroupProps {
  children:   React.ReactNode;
  className?: string;
  /** Stagger delay between children (seconds). Default: 0.1 */
  stagger?:   number;
  /** Animation preset applied to each child. Default: 'slide' */
  animation?: AnimationPreset;
  /** IntersectionObserver threshold. Default: 0.10 */
  threshold?: number;
}

/**
 * Wraps children in a staggered reveal container.
 * Each direct child is automatically delayed by `stagger` seconds.
 *
 * Reduced-motion users see all children immediately (no stagger).
 */
export function MotionGroup({
  children,
  className = '',
  stagger   = 0.10,
  animation = 'slide',
  threshold = 0.10,
}: MotionGroupProps) {
  const shouldReduceMotion = useSystemReducedMotion();
  const items = React.Children.toArray(children);

  if (shouldReduceMotion) {
    return <div className={className}>{children}</div>;
  }

  return (
    <div className={className}>
      {items.map((child, i) => (
        <Motion
          key={i}
          animation={animation}
          delay={i * stagger}
          threshold={threshold}
        >
          {child}
        </Motion>
      ))}
    </div>
  );
}

'use client';

import React from 'react';

export function Scene3D({ children }: { children?: React.ReactNode }) {
  return (
    <div className="w-full h-64 bg-gray-900 border border-gray-800 rounded-xl relative overflow-hidden flex items-center justify-center">
      <span className="text-gray-500 absolute bottom-4 right-4 text-xs font-mono">WebGPU Ready</span>
      <div className="text-cyan-400 font-bold tracking-widest">[ 3D Scene Container ]</div>
      {children}
    </div>
  );
}

export function AnimatedModel({ url }: { url: string }) {
  return <div className="p-4 border border-dashed border-cyan-500/30 text-cyan-500/50">Model: {url}</div>;
}

export function ParticleSystem({ count: _count = 1000 }: { count?: number }) {
  return <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-cyan-900/20 to-transparent pointer-events-none opacity-50" />;
}

#!/usr/bin/env node
/**
 * scripts/generate-hash.js
 *
 * Generates a bcrypt password hash to put in OWNER_PASSWORD_HASH.
 *
 * Usage:
 *   node scripts/generate-hash.js
 *
 * Then paste the output into your .env.local:
 *   OWNER_PASSWORD_HASH="$2b$12$..."
 */

const bcrypt = require('bcryptjs');
const readline = require('readline');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: true,
});

// Hide input while typing
function askPassword(prompt) {
  return new Promise((resolve) => {
    process.stdout.write(prompt);
    let password = '';

    // If running in a TTY, hide input
    if (process.stdin.isTTY) {
      process.stdin.setRawMode(true);
      process.stdin.resume();
      process.stdin.setEncoding('utf8');

      const onData = (ch) => {
        ch = ch.toString();
        if (ch === '\r' || ch === '\n') {
          process.stdin.setRawMode(false);
          process.stdin.pause();
          process.stdin.removeListener('data', onData);
          process.stdout.write('\n');
          resolve(password);
        } else if (ch === '\u0003') {
          // Ctrl+C
          process.exit();
        } else if (ch === '\u007F') {
          // Backspace
          if (password.length > 0) {
            password = password.slice(0, -1);
            process.stdout.clearLine(0);
            process.stdout.cursorTo(0);
            process.stdout.write(prompt + '*'.repeat(password.length));
          }
        } else {
          password += ch;
          process.stdout.write('*');
        }
      };

      process.stdin.on('data', onData);
    } else {
      // Fallback for non-TTY (e.g. piped input)
      rl.question('', (answer) => resolve(answer));
    }
  });
}

async function main() {
  console.log('');
  console.log('  ╔══════════════════════════════════════════════╗');
  console.log('  ║   AI UI Engine — Password Hash Generator     ║');
  console.log('  ╚══════════════════════════════════════════════╝');
  console.log('');

  const password = await askPassword('  Enter your desired password:');
  const password2 = await askPassword('  Confirm password:            ');

  if (password !== password2) {
    console.error('\n  ✗ Passwords do not match. Exiting.\n');
    process.exit(1);
  }

  if (password.length < 8) {
    console.error('\n  ✗ Password must be at least 8 characters.\n');
    process.exit(1);
  }

  console.log('\n  Generating bcrypt hash (cost=12)…');
  const hash = await bcrypt.hash(password, 12);

  console.log('\n  ✔ Success! Add these lines to your .env.local:\n');
  console.log('  ─────────────────────────────────────────────────');
  console.log(`  OWNER_EMAIL="shekhargiri005@gmail.com"`);
  console.log(`  OWNER_PASSWORD_HASH="${hash}"`);
  console.log('  ─────────────────────────────────────────────────');
  console.log('');
  console.log('  ⚠  Never commit .env.local to git.\n');

  rl.close();
  process.exit(0);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

const fs = require('fs');

try {
  let content = fs.readFileSync('.env', 'utf-8');
  // Replace the password hash with the bcrypt hash for 'password123'
  // using regex to match exact setting.
  content = content.replace(/OWNER_PASSWORD_HASH="[^"]*"/g, 'OWNER_PASSWORD_HASH="$2b$12$UPxLcNK8Q5/XDAtK1SyoU.8pUUrtFEB2bwdhC1UFV4Siy0I1wfvZqy"');

  if (!content.includes('OWNER_PASSWORD_HASH=')) {
    content += '\nOWNER_PASSWORD_HASH="$2b$12$UPxLcNK8Q5/XDAtK1SyoU.8pUUrtFEB2bwdhC1UFV4Siy0I1wfvZqy"';
  }

  // Also extract the email to let the user know what email to use.
  const emailMatch = content.match(/OWNER_EMAIL="([^"]+)"/);
  if (emailMatch) {
    console.log(`Email found: ${emailMatch[1]}`);
  } else {
    console.log('No OWNER_EMAIL found in config.');
  }

  fs.writeFileSync('.env', content, 'utf-8');
  console.log('Password hash successfully reset to "password123".');
} catch(e) {
  console.error("Error reading or writing to .env", e);
}

/**
 * seed-workspace-db.mjs
 * ─────────────────────
 * Seeds the local SQLite workspace.db with:
 *  1. A default WorkspaceSettings row (provider = "openai" placeholder — replace with your key)
 *  2. A sample UsageLog row to verify the table is writable
 *
 * Run with:
 *   node scripts/seed-workspace-db.mjs
 *
 * Or to reset and re-seed:
 *   node scripts/seed-workspace-db.mjs --reset
 */
import { readFileSync, writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';

const __dir  = dirname(fileURLToPath(import.meta.url));
const dbPath = resolve(__dir, '../data/projects/workspace.db');

// ─────────────────────────────────────────────────────────────────────────────
// Minimal SQLite INSERT writer (no npm deps needed)
// We use Prisma's own CLI to run raw SQL via `prisma db execute` so we don't
// need better-sqlite3.
// ─────────────────────────────────────────────────────────────────────────────
import { execSync } from 'child_process';

const reset = process.argv.includes('--reset');

const WORKSPACE_ID  = 'default';
const now           = new Date().toISOString();

// Build the SQL to seed WorkspaceSettings + UsageLog
const workspaceSettingsId = crypto.randomUUID();
const usageLogId          = crypto.randomUUID();

// Dummy encrypted key placeholder — replace with a real bcrypt/AES-encrypted key
// in production.  For local dev this is just a recognisable stub.
const encryptedApiKeyPlaceholder = 'PLACEHOLDER_SET_REAL_KEY_IN_ENV';

const resetSQL = reset ? `
DELETE FROM "WorkspaceSettings";
DELETE FROM "UsageLog";
` : '';

const seedSQL = `
${resetSQL}

-- WorkspaceSettings: default workspace, openai provider
INSERT OR IGNORE INTO "WorkspaceSettings" ("id","workspaceId","provider","model","encryptedApiKey","updatedAt")
VALUES (
  '${workspaceSettingsId}',
  '${WORKSPACE_ID}',
  'openai',
  'gpt-4o',
  '${encryptedApiKeyPlaceholder}',
  '${now}'
);

-- UsageLog: seed a zero-cost row so the table shows as active
INSERT OR IGNORE INTO "UsageLog"
  ("id","workspaceId","provider","model","promptTokens","completionTokens","totalTokens","latencyMs","costUsd","cached","createdAt")
VALUES (
  '${usageLogId}',
  '${WORKSPACE_ID}',
  'openai',
  'gpt-4o',
  0, 0, 0, 0, 0.0, false,
  '${now}'
);
`.trim();

// Write the SQL to a temp file (avoids shell-escaping nightmares)
const sqlFile = resolve(__dir, '../tmp/seed-workspace.sql');
writeFileSync(sqlFile, seedSQL, 'utf8');
console.log('SQL to execute:\n', seedSQL, '\n');

// Run via prisma db execute (uses the dev DATABASE_URL = sqlite dev.db by default)
// For workspace.db we feed it via --url directly.
try {
  execSync(
    `npx prisma db execute --url "file:./data/projects/workspace.db" --file tmp/seed-workspace.sql`,
    { cwd: resolve(__dir, '..'), stdio: 'inherit' }
  );
  console.log('\n✅ workspace.db seeded successfully!');
  console.log('   WorkspaceSettings id :', workspaceSettingsId);
  console.log('   UsageLog id          :', usageLogId);
  console.log('\n⚠️  Remember to UPDATE the encryptedApiKey with your real key.');
} catch (err) {
  console.error('\n❌ Seed failed:', err.message);
  console.log('\nFallback: run this SQL manually in your SQLite client:');
  console.log(seedSQL);
  process.exit(1);
}
